+++ b/src/shared/types.ts
@@ -0,0 +1,281 @@
+export type Provider = "openai" | "anthropic";
+export type Locale = "en" | "zh";
+
+export type MessageRole = "system" | "user" | "assistant";
+
+export type ChatMessage = {
+  role: MessageRole;
+  content: string;
+};
+
+export type ProviderSettings = {
+  id: string;
+  name: string;
+  provider: Provider;
+  apiKey: string;
+  baseUrl?: string;
+  models: string[];
+  defaultModel: string;
+  enabled: boolean;
+};
+
+export type ModelUsage = {
+  inputTokens?: number;
+  outputTokens?: number;
+  totalTokens?: number;
+};
+
+export type ModelRequest = {
+  messages: ChatMessage[];
+  model?: string;
+  maxTokens?: number;
+  temperature?: number;
+  timeoutMs?: number;
+};
+
+export type ModelResponse = {
+  provider: Provider;
+  model: string;
+  text: string;
+  usage?: ModelUsage;
+  raw?: unknown;
+};
+
+export type ModelGateway = {
+  chat(messages: ChatMessage[]): Promise<ModelResponse>;
+};
+
+export type Scope = "model.chat" | "page.read" | "page.act" | "agent.run" | "debugger.control";
+export type AgentControlMode = "dom" | "debugger" | "auto";
+
+export type SitePermission = {
+  origin: string;
+  appName?: string;
+  scopes: Scope[];
+  autoRun: boolean;
+  createdAt: string;
+  updatedAt: string;
+  lastUsedAt?: string;
+  revokedAt?: string;
+};
+
+export type CallSource = "sidebar" | "gateway";
+export type CallType = "access" | "chat" | "run";
+export type CallStatus = "success" | "failed" | "denied" | "canceled" | "revoked";
+
+export type CallLog = {
+  id: string;
+  source: CallSource;
+  origin?: string;
+  type: CallType;
+  model?: string;
+  status: CallStatus;
+  createdAt: string;
+  summary?: string;
+};
+
+export type DebugLog = {
+  id: string;
+  callId?: string;
+  createdAt: string;
+  title: string;
+  details: unknown;
+};
+
+export type GatewaySettings = {
+  enabled: boolean;
+};
+
+export type ExtensionSettings = {
+  locale: Locale;
+  providers: ProviderSettings[];
+  defaultProviderId?: string;
+  defaultModel?: string;
+  gateway: GatewaySettings;
+  skills: InstalledSkill[];
+  permissions: SitePermission[];
+  callLogs: CallLog[];
+  debugLogs: DebugLog[];
+};
+
+export type InteractiveElement = {
+  selector: string;
+  tagName: string;
+  label: string;
+  role?: string;
+};
+
+export type DomObservation = {
+  title: string;
+  url: string;
+  origin: string;
+  text: string;
+  selectedText?: string;
+  headings: string[];
+  links: Array<{ text: string; href: string }>;
+  interactiveElements: InteractiveElement[];
+};
+
+export type DomAction =
+  | { type: "click"; selector: string }
+  | { type: "type"; selector: string; value: string }
+  | { type: "scroll"; direction: "up" | "down"; amount?: number };
+
+export type AgentReadAction = { type: "read" };
+export type AgentDebuggerAction = { type: "debugger"; reason?: string };
+export type AgentSkillAction = { type: "skill"; skillId: string; input?: Record<string, unknown> };
+export type AgentAction = DomAction | AgentReadAction | AgentDebuggerAction | AgentSkillAction;
+export type AgentActionStatus = "success" | "failed" | "needs_confirmation" | "blocked";
+
+export type DomActionResult = {
+  ok: boolean;
+  status?: AgentActionStatus;
+  message: string;
+};
+
+export type DebuggerSnapshot = DomObservation & {
+  source: "debugger";
+  document?: unknown;
+  accessibilityTree?: unknown[];
+};
+
+export type DebuggerAction =
+  | { type: "attach" }
+  | { type: "detach" }
+  | { type: "snapshot" }
+  | { type: "screenshot"; fullPage?: boolean }
+  | { type: "click"; x: number; y: number }
+  | { type: "click"; selector: string }
+  | { type: "type"; text: string; selector?: string }
+  | { type: "scroll"; direction: "up" | "down"; amount?: number }
+  | { type: "wait"; ms?: number };
+
+export type DebuggerActionResult = {
+  ok: boolean;
+  message: string;
+  observation?: DebuggerSnapshot;
+  screenshot?: PageScreenshot;
+  rewrite?: PageRewriteResult;
+  formFill?: FormFillResult;
+};
+
+export type PageScreenshot = {
+  dataUrl: string;
+  mimeType: "image/png";
+  width: number;
+  height: number;
+  filename: string;
+};
+
+export type PageTextReplacement = {
+  index: number;
+  original: string;
+  replacement: string;
+};
+
+export type PageRewriteResult = {
+  sessionId: string;
+  changed: number;
+  replacements: PageTextReplacement[];
+};
+
+export type FormFillField = {
+  selector: string;
+  value: string;
+};
+
+export type FormFillResult = {
+  filled: number;
+  skipped: Array<{ selector: string; reason: string }>;
+};
+
+export type BenchmarkToolRequest =
+  | { type: "screenshot" }
+  | { type: "report" }
+  | { type: "rewrite"; instruction: string }
+  | { type: "restore-rewrite"; sessionId?: string }
+  | { type: "fill-form"; instruction: string };
+
+export type InstalledSkill = {
+  id: string;
+  name: string;
+  description: string;
+  skillMarkdown: string;
+  enabled: boolean;
+  source: "builtin" | "skills.sh" | "manual";
+  sourceUrl?: string;
+  installedAt?: string;
+  updatedAt?: string;
+};
+
+export type BenchmarkToolResult =
+  | { type: "screenshot"; title: string; screenshot: PageScreenshot }
+  | { type: "report"; title: string; html: string }
+  | { type: "rewrite"; title: string; rewrite: PageRewriteResult }
+  | { type: "restore-rewrite"; title: string; restored: number }
+  | { type: "fill-form"; title: string; formFill: FormFillResult };
+
+export type AgentEvent =
+  | { type: "observe"; observation: DomObservation }
+  | { type: "thought"; text: string; confidence?: number }
+  | { type: "plan"; text: string; confidence?: number }
+  | { type: "action"; action: AgentAction; reason: string; confidence?: number }
+  | { type: "action-result"; action: AgentAction; result: DomActionResult }
+  | { type: "blocked"; reason: string; status: "needs_confirmation" | "blocked" }
+  | { type: "final"; text: string };
+
+export type GatewayErrorCode =
+  | "permission_denied"
+  | "model_not_configured"
+  | "user_rejected"
+  | "gateway_disabled"
+  | "page_unavailable"
+  | "page_not_operable"
+  | "debugger_control_unavailable"
+  | "invalid_request"
+  | "internal_error";
+
+export type GatewayMethod = "requestAccess" | "getStatus" | "chat" | "run" | "models.list";
+
+export type BrowserAgentRequest =
+  | { id: string; requestId: string; source: "agenticify-page"; version: "1"; method: "requestAccess"; payload: AccessRequestPayload }
+  | { id: string; requestId: string; source: "agenticify-page"; version: "1"; method: "getStatus"; payload?: undefined }
+  | { id: string; requestId: string; source: "agenticify-page"; version: "1"; method: "chat"; payload: ChatPayload }
+  | { id: string; requestId: string; source: "agenticify-page"; version: "1"; method: "run"; payload: RunPayload }
+  | { id: string; requestId: string; source: "agenticify-page"; version: "1"; method: "models.list"; payload?: undefined };
+
+export type GatewayError = {
+  code: GatewayErrorCode;
+  message: string;
+  details?: unknown;
+};
+
+export type BrowserAgentResponse =
+  | { id: string; requestId: string; source: "agenticify-extension"; ok: true; result: unknown }
+  | { id: string; requestId: string; source: "agenticify-extension"; ok: false; code: GatewayErrorCode; error: GatewayError };
+
+export type AccessRequestPayload = {
+  appName?: string;
+  scopes: Scope[];
+  reason?: string;
+  autoRun?: boolean;
+};
+
+export type PendingAccessRequest = {
+  id: string;
+  origin: string;
+  appName?: string;
+  scopes: Scope[];
+  reason?: string;
+  requestedAutoRun: boolean;
+  createdAt: string;
+};
+
+export type ChatPayload = {
+  messages: ChatMessage[];
+};
+
+export type RunPayload = {
+  task: string;
+  mode?: AgentControlMode;
+};

diff --git a/src/agent/skills.ts b/src/agent/skills.ts
new file mode 100644
index 0000000..7a7cfba
--- /dev/null
+++ b/src/agent/skills.ts
@@ -0,0 +1,165 @@
+import type { AgentSkillAction, BenchmarkToolRequest, InstalledSkill } from "../shared/types";
+
+type ParseOptions = {
+  source?: InstalledSkill["source"];
+  sourceUrl?: string;
+  now?: string;
+};
+
+type GitHubContentsResponse = {
+  content?: string;
+  encoding?: string;
+};
+
+const builtInSkillMarkdown = {
+  screenshot: `---
+name: screenshot
+description: Capture a screenshot of the current browser page.
+---
+
+Use this skill when the user asks for a page screenshot, screen capture, visual capture, or PNG export.
+Action protocol: return {"action":{"type":"skill","skillId":"builtin/screenshot"},"reason":"...","confidence":0.9}.`,
+  pageReport: `---
+name: page-report
+description: Create an HTML analysis report from the current page content.
+---
+
+Use this skill when the user asks for an analysis report, HTML report, page summary report, or exportable report.
+Action protocol: return {"action":{"type":"skill","skillId":"builtin/page-report"},"reason":"...","confidence":0.9}.`,
+  rewritePage: `---
+name: rewrite-page
+description: Rewrite or translate visible page copy by safely changing DOM text nodes.
+---
+
+Use this skill when the user asks to translate or rewrite the current page copy.
+Action protocol: return {"action":{"type":"skill","skillId":"builtin/rewrite-page","input":{"instruction":"user rewrite request"}},"reason":"...","confidence":0.9}.`,
+  fillForm: `---
+name: fill-form
+description: Fill page form fields from the user's description without submitting the form.
+---
+
+Use this skill when the user asks to fill a form from provided details.
+Action protocol: return {"action":{"type":"skill","skillId":"builtin/fill-form","input":{"instruction":"user form filling request"}},"reason":"...","confidence":0.9}.`
+} as const;
+
+function slugify(value: string): string {
+  return value.toLowerCase().trim().replace(/[^a-z0-9]+/g, "-").replace(/^-|-$/g, "") || "skill";
+}
+
+function parseFrontmatter(markdown: string): Record<string, string> {
+  const match = /^---\s*\n([\s\S]*?)\n---\s*/.exec(markdown);
+  if (!match) return {};
+
+  return Object.fromEntries(
+    match[1]
+      .split("\n")
+      .map((line) => line.match(/^([A-Za-z0-9_-]+):\s*(.*)$/))
+      .filter((entry): entry is RegExpMatchArray => Boolean(entry))
+      .map((entry) => [entry[1], entry[2].replace(/^["']|["']$/g, "").trim()])
+  );
+}
+
+function bodyText(markdown: string): string {
+  return markdown.replace(/^---\s*\n[\s\S]*?\n---\s*/, "").trim();
+}
+
+export function parseSkillMarkdown(markdown: string, options: ParseOptions = {}): InstalledSkill {
+  const frontmatter = parseFrontmatter(markdown);
+  const name = frontmatter.name?.trim();
+  const description = frontmatter.description?.trim();
+  if (!name || !description) {
+    throw new Error("SKILL.md must include frontmatter name and description.");
+  }
+  const now = options.now ?? new Date().toISOString();
+  return {
+    id: slugify(name),
+    name,
+    description,
+    skillMarkdown: markdown,
+    enabled: true,
+    source: options.source ?? (options.sourceUrl?.startsWith("https://skills.sh/") ? "skills.sh" : "manual"),
+    sourceUrl: options.sourceUrl,
+    installedAt: now,
+    updatedAt: now
+  };
+}
+
+export const builtInSkills: InstalledSkill[] = [
+  { ...parseSkillMarkdown(builtInSkillMarkdown.screenshot, { source: "builtin", now: "builtin" }), id: "builtin/screenshot" },
+  { ...parseSkillMarkdown(builtInSkillMarkdown.pageReport, { source: "builtin", now: "builtin" }), id: "builtin/page-report" },
+  { ...parseSkillMarkdown(builtInSkillMarkdown.rewritePage, { source: "builtin", now: "builtin" }), id: "builtin/rewrite-page" },
+  { ...parseSkillMarkdown(builtInSkillMarkdown.fillForm, { source: "builtin", now: "builtin" }), id: "builtin/fill-form" }
+];
+
+function decodeBase64(value: string): string {
+  if (typeof atob === "function") return atob(value);
+  return Buffer.from(value, "base64").toString("utf8");
+}
+
+export async function installSkillFromUrl(url: string, fetchImpl: typeof fetch = fetch): Promise<InstalledSkill> {
+  const parsed = new URL(url);
+  if (parsed.hostname !== "skills.sh") {
+    throw new Error("Only skills.sh skill URLs are supported.");
+  }
+  const [owner, repo, ...skillParts] = parsed.pathname.split("/").filter(Boolean);
+  const skillPath = skillParts.join("/");
+  if (!owner || !repo || !skillPath) {
+    throw new Error("skills.sh URL must include owner, repo, and skill path.");
+  }
+
+  const apiUrl = `https://api.github.com/repos/${owner}/${repo}/contents/${skillPath}/SKILL.md`;
+  const response = await fetchImpl(apiUrl);
+  if (!response.ok) throw new Error(`Could not download SKILL.md from ${url}.`);
+  const payload = await response.json() as GitHubContentsResponse;
+  const markdown = payload.encoding === "base64" && payload.content
+    ? decodeBase64(payload.content.replace(/\s+/g, ""))
+    : payload.content ?? "";
+  return parseSkillMarkdown(markdown, { source: "skills.sh", sourceUrl: url });
+}
+
+export function matchSkillsForTask(task: string, skills: InstalledSkill[], limit = 4): InstalledSkill[] {
+  const tokens = new Set(task.toLowerCase().split(/[^a-z0-9\u4e00-\u9fff]+/).filter((token) => token.length >= 2));
+  return skills
+    .filter((skill) => skill.enabled)
+    .map((skill) => {
+      const haystack = `${skill.name} ${skill.description} ${bodyText(skill.skillMarkdown)}`.toLowerCase();
+      const score = [...tokens].filter((token) => haystack.includes(token)).length;
+      return { skill, score };
+    })
+    .filter((entry) => entry.score > 0)
+    .sort((left, right) => right.score - left.score)
+    .slice(0, limit)
+    .map((entry) => entry.skill);
+}
+
+export function buildSkillPrompt(skills: InstalledSkill[]): string {
+  if (!skills.length) return "";
+  return [
+    "Available installed skills:",
+    ...skills.map((skill) => [
+      `Skill: ${skill.id}`,
+      `Name: ${skill.name}`,
+      `Description: ${skill.description}`,
+      skill.skillMarkdown
+    ].join("\n"))
+  ].join("\n\n");
+}
+
+function actionInstruction(action: AgentSkillAction): string {
+  const value = action.input?.instruction;
+  return typeof value === "string" && value.trim() ? value.trim() : "";
+}
+
+export function skillActionToBenchmarkRequest(action: AgentSkillAction): BenchmarkToolRequest | undefined {
+  if (action.skillId === "builtin/screenshot") return { type: "screenshot" };
+  if (action.skillId === "builtin/page-report") return { type: "report" };
+  if (action.skillId === "builtin/rewrite-page") return { type: "rewrite", instruction: actionInstruction(action) };
+  if (action.skillId === "builtin/fill-form") return { type: "fill-form", instruction: actionInstruction(action) };
+  return undefined;
+}
+
+export function mergeSkills(installed: InstalledSkill[]): InstalledSkill[] {
+  const byId = new Map<string, InstalledSkill>();
+  for (const skill of [...builtInSkills, ...installed]) byId.set(skill.id, skill);
+  return [...byId.values()];
+}

