+  while ((match = pattern.exec(text)) !== null) {
+    if (match.index > cursor) {
+      blocks.push({ type: "text", content: text.slice(cursor, match.index) });
+    }
+    blocks.push({
+      type: "code",
+      language: match[1]?.trim() || undefined,
+      content: match[2].replace(/\n$/, "")
